{"command": "cd /tmp/sv-ac84776b9b8b47a1b73e9146079b8462/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)
print('=== Comparison ===')
changes = False
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key, 'MISSING')
    av = a.get(key, 'MISSING')
    status = 'unchanged' if bv == av else 'CHANGED'
    if status == 'CHANGED': changes = True
    print(f'{key[0]:20s} {key[1]:55s} {bv:>10s} -> {av:>10s}  [{status}]')
if not changes: print('\\nAll packages resolve identically. Conversion is version-neutral.')
"", "description": "Compare baseline vs post-CPM packages", "initial_wait": 30}

